// EmployeeDataStore.java
package com.hr.datastore;

import com.hr.model.Employee;
import com.hr.model.PerformanceReview;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.atomic.AtomicInteger;

public class EmployeeDataStore {
    private static EmployeeDataStore instance;
    private final Map<Integer, Employee> employees = new ConcurrentHashMap<>();
    private final Map<Integer, List<PerformanceReview>> reviewHistory = new ConcurrentHashMap<>();
    private final AtomicInteger reviewIdCounter = new AtomicInteger(1000);

    private EmployeeDataStore() {
        initializeSampleData();
    }

    public static synchronized EmployeeDataStore getInstance() {
        if (instance == null) {
            instance = new EmployeeDataStore();
        }
        return instance;
    }

    private void initializeSampleData() {
        addEmployee(new Employee(1001, "John", "Smith", "john.smith@company.com", "Engineering", "Senior Developer", 95000.00));
        addEmployee(new Employee(1002, "Jane", "Doe", "jane.doe@company.com", "Marketing", "Marketing Manager", 85000.00));
        addEmployee(new Employee(1003, "Robert", "Johnson", "robert.johnson@company.com", "Engineering", "Tech Lead", 120000.00));
        addEmployee(new Employee(1004, "Emily", "Williams", "emily.williams@company.com", "HR", "HR Specialist", 70000.00));
        addEmployee(new Employee(1005, "Michael", "Brown", "michael.brown@company.com", "Finance", "Financial Analyst", 80000.00));
        addEmployee(new Employee(1006, "Sarah", "Davis", "sarah.davis@company.com", "Engineering", "Junior Developer", 65000.00));
        addEmployee(new Employee(1007, "David", "Wilson", "david.wilson@company.com", "Sales", "Sales Director", 110000.00));
    }

    public void addEmployee(Employee employee) {
        employees.put(employee.getEmployeeId(), employee);
        reviewHistory.putIfAbsent(employee.getEmployeeId(), new CopyOnWriteArrayList<>());
    }

    public Employee getEmployee(int employeeId) {
        return employees.get(employeeId);
    }

    public List<Employee> getAllEmployees() {
        return new ArrayList<>(employees.values());
    }

    public List<Employee> getEmployeesByDepartment(String department) {
        List<Employee> result = new ArrayList<>();
        for (Employee emp : employees.values()) {
            if (emp.getDepartment().equalsIgnoreCase(department)) {
                result.add(emp);
            }
        }
        return result;
    }

    public List<Employee> getActiveEmployees() {
        List<Employee> result = new ArrayList<>();
        for (Employee emp : employees.values()) {
            if ("ACTIVE".equals(emp.getStatus())) {
                result.add(emp);
            }
        }
        return result;
    }

    public void addReview(int employeeId, PerformanceReview review) {
        reviewHistory.computeIfAbsent(employeeId, k -> new CopyOnWriteArrayList<>()).add(review);
    }

    public List<PerformanceReview> getReviewHistory(int employeeId) {
        return reviewHistory.getOrDefault(employeeId, new ArrayList<>());
    }

    public int getNextReviewId() {
        return reviewIdCounter.incrementAndGet();
    }

    public boolean employeeExists(int employeeId) {
        return employees.containsKey(employeeId);
    }
}

