// EmployeeManagementServiceImpl.java
package com.hr.service;

import com.hr.datastore.EmployeeDataStore;
import com.hr.model.*;

import javax.jws.WebService;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    endpointInterface = "com.hr.service.EmployeeManagementService",
    serviceName = "EmployeeManagementService",
    portName = "EmployeeManagementPort",
    targetNamespace = "http://service.hr.com/employee",
    wsdlLocation = "EmployeeManagementService.wsdl"
)
public class EmployeeManagementServiceImpl implements EmployeeManagementService {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServiceImpl.class.getName());
    private final EmployeeDataStore dataStore = EmployeeDataStore.getInstance();

    private static final double MAX_SALARY_INCREASE_PERCENTAGE = 50.0;
    private static final double MIN_SALARY = 30000.0;
    private static final double MAX_SALARY = 500000.0;
    private static final double MIN_PERFORMANCE_SCORE = 1.0;
    private static final double MAX_PERFORMANCE_SCORE = 5.0;

    @Override
    public Employee getEmployee(int employeeId) {
        LOGGER.info("Fetching employee with ID: " + employeeId);
        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            LOGGER.warning("Employee not found with ID: " + employeeId);
        }
        return employee;
    }

    @Override
    public List<Employee> getAllEmployees() {
        LOGGER.info("Fetching all employees");
        return dataStore.getAllEmployees();
    }

    @Override
    public List<Employee> getEmployeesByDepartment(String department) {
        LOGGER.info("Fetching employees for department: " + department);
        if (department == null || department.trim().isEmpty()) {
            LOGGER.warning("Department name is null or empty");
            return new ArrayList<>();
        }
        return dataStore.getEmployeesByDepartment(department);
    }

    @Override
    public List<Employee> getActiveEmployees() {
        LOGGER.info("Fetching active employees");
        return dataStore.getActiveEmployees();
    }

    @Override
    public SalaryUpdateResult updateSalary(int employeeId, double newSalary, String reason, String approvedBy) {
        LOGGER.info("Updating salary for employee " + employeeId + " to " + newSalary);

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            return new SalaryUpdateResult(false, "Employee not found with ID: " + employeeId, employeeId, 0, 0);
        }

        if (!"ACTIVE".equals(employee.getStatus())) {
            return new SalaryUpdateResult(false, "Cannot update salary for non-active employee. Current status: " + employee.getStatus(), employeeId, employee.getSalary(), employee.getSalary());
        }

        if (newSalary < MIN_SALARY || newSalary > MAX_SALARY) {
            return new SalaryUpdateResult(false, "New salary must be between " + MIN_SALARY + " and " + MAX_SALARY, employeeId, employee.getSalary(), employee.getSalary());
        }

        if (reason == null || reason.trim().isEmpty()) {
            return new SalaryUpdateResult(false, "Reason for salary update is required", employeeId, employee.getSalary(), employee.getSalary());
        }

        if (approvedBy == null || approvedBy.trim().isEmpty()) {
            return new SalaryUpdateResult(false, "Approver name is required", employeeId, employee.getSalary(), employee.getSalary());
        }

        double previousSalary = employee.getSalary();
        double increasePercentage = ((newSalary - previousSalary) / previousSalary) * 100;

        if (increasePercentage > MAX_SALARY_INCREASE_PERCENTAGE) {
            return new SalaryUpdateResult(false, "Salary increase exceeds maximum allowed percentage of " + MAX_SALARY_INCREASE_PERCENTAGE + "%. Requested: " + String.format("%.2f", increasePercentage) + "%", employeeId, previousSalary, previousSalary);
        }

        employee.setSalary(newSalary);

        LOGGER.info("Salary updated for employee " + employeeId + ": " + previousSalary + " -> " + newSalary + " (Approved by: " + approvedBy + ", Reason: " + reason + ")");

        return new SalaryUpdateResult(true, "Salary updated successfully. Approved by: " + approvedBy + ". Reason: " + reason, employeeId, previousSalary, newSalary);
    }

    @Override
    public SalaryUpdateResult applySalaryIncreaseByPercentage(int employeeId, double percentage, String reason, String approvedBy) {
        LOGGER.info("Applying " + percentage + "% salary increase for employee " + employeeId);

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            return new SalaryUpdateResult(false, "Employee not found with ID: " + employeeId, employeeId, 0, 0);
        }

        if (percentage <= 0 || percentage > MAX_SALARY_INCREASE_PERCENTAGE) {
            return new SalaryUpdateResult(false, "Percentage must be between 0 and " + MAX_SALARY_INCREASE_PERCENTAGE, employeeId, employee.getSalary(), employee.getSalary());
        }

        double newSalary = employee.getSalary() * (1 + percentage / 100);
        return updateSalary(employeeId, newSalary, reason + " (Percentage increase: " + percentage + "%)", approvedBy);
    }

    @Override
    public List<SalaryUpdateResult> applyDepartmentWideSalaryIncrease(String department, double percentage, String approvedBy) {
        LOGGER.info("Applying " + percentage + "% salary increase for department: " + department);
        List<SalaryUpdateResult> results = new ArrayList<>();

        if (department == null || department.trim().isEmpty()) {
            SalaryUpdateResult errorResult = new SalaryUpdateResult();
            errorResult.setSuccess(false);
            errorResult.setMessage("Department name is required");
            results.add(errorResult);
            return results;
        }

        List<Employee> departmentEmployees = dataStore.getEmployeesByDepartment(department);
        if (departmentEmployees.isEmpty()) {
            SalaryUpdateResult errorResult = new SalaryUpdateResult();
            errorResult.setSuccess(false);
            errorResult.setMessage("No employees found in department: " + department);
            results.add(errorResult);
            return results;
        }

        for (Employee emp : departmentEmployees) {
            if ("ACTIVE".equals(emp.getStatus())) {
                SalaryUpdateResult result = applySalaryIncreaseByPercentage(
                    emp.getEmployeeId(), percentage,
                    "Department-wide salary increase for " + department,
                    approvedBy
                );
                results.add(result);
            }
        }

        return results;
    }

    @Override
    public PerformanceReviewResult submitPerformanceReview(int employeeId, String reviewerName,
            double score, String category, String notes, String strengths,
            String areasForImprovement, String goals,
            boolean recommendPromotion, boolean recommendSalaryIncrease) {

        LOGGER.info("Submitting performance review for employee " + employeeId);

        PerformanceReviewResult result = new PerformanceReviewResult();
        result.setEmployeeId(employeeId);

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            result.setSuccess(false);
            result.setMessage("Employee not found with ID: " + employeeId);
            return result;
        }

        if (!"ACTIVE".equals(employee.getStatus())) {
            result.setSuccess(false);
            result.setMessage("Cannot submit review for non-active employee. Current status: " + employee.getStatus());
            return result;
        }

        if (score < MIN_PERFORMANCE_SCORE || score > MAX_PERFORMANCE_SCORE) {
            result.setSuccess(false);
            result.setMessage("Performance score must be between " + MIN_PERFORMANCE_SCORE + " and " + MAX_PERFORMANCE_SCORE);
            return result;
        }

        if (reviewerName == null || reviewerName.trim().isEmpty()) {
            result.setSuccess(false);
            result.setMessage("Reviewer name is required");
            return result;
        }

        if (category == null || !isValidCategory(category)) {
            result.setSuccess(false);
            result.setMessage("Invalid category. Valid categories: ANNUAL, QUARTERLY, PROBATION, IMPROVEMENT_PLAN");
            return result;
        }

        PerformanceReview review = new PerformanceReview();
        int reviewId = dataStore.getNextReviewId();
        review.setReviewId(reviewId);
        review.setEmployeeId(employeeId);
        review.setReviewerName(reviewerName);
        review.setScore(score);
        review.setCategory(category);
        review.setNotes(notes);
        review.setStrengths(strengths);
        review.setAreasForImprovement(areasForImprovement);
        review.setGoals(goals);
        review.setReviewDate(new Date());
        review.setRecommendPromotion(recommendPromotion);
        review.setRecommendSalaryIncrease(recommendSalaryIncrease);

        dataStore.addReview(employeeId, review);

        double avgScore = calculateAverageScore(employeeId);
        employee.setPerformanceScore(avgScore);
        employee.setLastReviewNotes(notes);
        employee.setLastReviewDate(new Date());

        String rating = getPerformanceRating(avgScore);

        result.setSuccess(true);
        result.setReviewId(reviewId);
        result.setNewAverageScore(avgScore);
        result.setPerformanceRating(rating);
        result.setMessage("Performance review submitted successfully. Rating: " + rating +
            (recommendPromotion ? " [Promotion Recommended]" : "") +
            (recommendSalaryIncrease ? " [Salary Increase Recommended]" : ""));

        LOGGER.info("Performance review " + reviewId + " submitted for employee " + employeeId + ". Score: " + score + ", Rating: " + rating);

        return result;
    }

    @Override
    public List<PerformanceReview> getPerformanceReviewHistory(int employeeId) {
        LOGGER.info("Fetching performance review history for employee " + employeeId);
        return dataStore.getReviewHistory(employeeId);
    }

    @Override
    public double getAveragePerformanceScore(int employeeId) {
        return calculateAverageScore(employeeId);
    }

    @Override
    public TerminationResult terminateEmployee(int employeeId, String reason, String processedBy) {
        LOGGER.info("Processing termination for employee " + employeeId);

        TerminationResult result = new TerminationResult();
        result.setEmployeeId(employeeId);

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            result.setSuccess(false);
            result.setMessage("Employee not found with ID: " + employeeId);
            return result;
        }

        if ("TERMINATED".equals(employee.getStatus())) {
            result.setSuccess(false);
            result.setMessage("Employee is already terminated");
            result.setTerminationDate(employee.getTerminationDate());
            return result;
        }

        if (reason == null || reason.trim().isEmpty()) {
            result.setSuccess(false);
            result.setMessage("Termination reason is required");
            return result;
        }

        if (processedBy == null || processedBy.trim().isEmpty()) {
            result.setSuccess(false);
            result.setMessage("Processing HR representative name is required");
            return result;
        }

        Date terminationDate = new Date();
        double finalSettlement = calculateFinalSettlement(employee);

        employee.setStatus("TERMINATED");
        employee.setTerminationDate(terminationDate);

        result.setSuccess(true);
        result.setEmployeeName(employee.getFirstName() + " " + employee.getLastName());
        result.setTerminationDate(terminationDate);
        result.setTerminationReason(reason);
        result.setFinalSettlementAmount(finalSettlement);
        result.setMessage("Employee " + employee.getFirstName() + " " + employee.getLastName() +
            " has been terminated. Final settlement amount: $" + String.format("%.2f", finalSettlement) +
            ". Processed by: " + processedBy);

        LOGGER.info("Employee " + employeeId + " (" + employee.getFirstName() + " " + employee.getLastName() +
            ") terminated. Reason: " + reason + ". Processed by: " + processedBy);

        return result;
    }

    @Override
    public boolean reinstateEmployee(int employeeId, String processedBy) {
        LOGGER.info("Processing reinstatement for employee " + employeeId);

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            LOGGER.warning("Employee not found with ID: " + employeeId);
            return false;
        }

        if (!"TERMINATED".equals(employee.getStatus())) {
            LOGGER.warning("Employee " + employeeId + " is not terminated. Current status: " + employee.getStatus());
            return false;
        }

        employee.setStatus("ACTIVE");
        employee.setTerminationDate(null);

        LOGGER.info("Employee " + employeeId + " reinstated by " + processedBy);
        return true;
    }

    @Override
    public Employee addEmployee(int employeeId, String firstName, String lastName, String email,
                                 String department, String position, double salary) {
        LOGGER.info("Adding new employee: " + firstName + " " + lastName);

        if (dataStore.employeeExists(employeeId)) {
            LOGGER.warning("Employee with ID " + employeeId + " already exists");
            return null;
        }

        if (salary < MIN_SALARY || salary > MAX_SALARY) {
            LOGGER.warning("Invalid salary: " + salary);
            return null;
        }

        Employee employee = new Employee(employeeId, firstName, lastName, email, department, position, salary);
        dataStore.addEmployee(employee);

        LOGGER.info("New employee added: " + employee);
        return employee;
    }

    // Helper methods

    private boolean isValidCategory(String category) {
        return "ANNUAL".equals(category) || "QUARTERLY".equals(category) ||
               "PROBATION".equals(category) || "IMPROVEMENT_PLAN".equals(category);
    }

    private double calculateAverageScore(int employeeId) {
        List<PerformanceReview> reviews = dataStore.getReviewHistory(employeeId);
        if (reviews.isEmpty()) {
            return 0.0;
        }
        double total = 0;
        for (PerformanceReview review : reviews) {
            total += review.getScore();
        }
        return Math.round((total / reviews.size()) * 100.0) / 100.0;
    }

    private String getPerformanceRating(double averageScore) {
        if (averageScore >= 4.5) return "EXCEPTIONAL";
        if (averageScore >= 3.5) return "EXCEEDS_EXPECTATIONS";
        if (averageScore >= 2.5) return "MEETS_EXPECTATIONS";
        if (averageScore >= 1.5) return "NEEDS_IMPROVEMENT";
        return "UNSATISFACTORY";
    }

    private double calculateFinalSettlement(Employee employee) {
        // Simplified settlement: 1 month salary as base + pro-rated bonus based on performance
        double baseSeverance = employee.getSalary() / 12; // One month salary
        double performanceBonus = 0;

        if (employee.getPerformanceScore() >= 3.5) {
            performanceBonus = (employee.getSalary() / 12) * 0.5; // Half month bonus for good performers
        }

        // Calculate tenure bonus (simplified)
        if (employee.getHireDate() != null) {
            long tenureMillis = new Date().getTime() - employee.getHireDate().getTime();
            long tenureYears = tenureMillis / (1000L * 60 * 60 * 24 * 365);
            baseSeverance += (tenureYears * employee.getSalary() / 12) * 0.25; // Quarter month per year of service
        }

        return Math.round((baseSeverance + performanceBonus) * 100.0) / 100.0;
    }
}

// HRServicePublisher.java
package com.hr;

import com.hr.service.EmployeeManagementServiceImpl;

import javax.xml.ws.Endpoint;
import java.util.logging.Level;
import java.util.logging.Logger;

public class HRServicePublisher {

    private static final Logger LOGGER = Logger.getLogger(HRServicePublisher.class.getName());
    private static final String SERVICE_URL = "http://localhost:8080/hr/employee-management";

    private static Endpoint endpoint;

    public static void main(String[] args) {
        try {
            publishService();

            System.out.println("==============================================");
            System.out.println("  HR Employee Management SOAP Web Service");
            System.out.println("==============================================");
            System.out.println("Service URL: " + SERVICE_URL);
            System.out.println("WSDL URL:    " + SERVICE_URL + "?wsdl");
            System.out.println("==============================================");
            System.out.println("Available Operations:");
            System.out.println("  - getEmployee");
            System.out.println("  - getAllEmployees");
            System.out.println("  - getEmployeesByDepartment");
            System.out.println("  - getActiveEmployees");
            System.out.println("  - addEmployee");
            System.out.println("  - updateSalary");
            System.out.println("  - applySalaryIncreaseByPercentage");
            System.out.println("  - applyDepartmentWideSalaryIncrease");
            System.out.println("  - submitPerformanceReview");
            System.out.println("  - getPerformanceReviewHistory");
            System.out.println("  - getAveragePerformanceScore");
            System.out.println("  - terminateEmployee");
            System.out.println("  - reinstateEmployee");
            System.out.println("==============================================");
            System.out.println("Press Ctrl+C to stop the service...");

            // Add shutdown hook
            Runtime.getRuntime().addShutdownHook(new Thread(() -> {
                System.out.println("\nShutting down HR Service...");
                stopService();
                System.out.println("HR Service stopped.");
            }));

            // Keep the main thread alive
            Thread.currentThread().join();

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Failed to start HR Service", e);
            System.err.println("Failed to start service: " + e.getMessage());
        }
    }

    public static void publishService() {
        EmployeeManagementServiceImpl serviceImpl = new EmployeeManagementServiceImpl();
        endpoint = Endpoint.publish(SERVICE_URL, serviceImpl);
        LOGGER.info("HR Employee Management Service published at: " + SERVICE_URL);
    }

    public static void stopService() {
        if (endpoint != null && endpoint.isPublished()) {
            endpoint.stop();
            LOGGER.info("HR Employee Management Service stopped");
        }
    }
}

